import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../utils/api';
import { DatePicker } from '../components/common/DatePicker';
import Sidebar from '../components/common/Sidebar';

// ─── Core download helper ────────────────────────────────────────────────────
// Uses Axios (JWT token), handles both .xlsx and .csv responses automatically
const downloadCSV = async (endpoint, filename, setLoading) => {
  if (setLoading) setLoading(true);
  try {
    const response = await api.get(endpoint, { responseType: 'blob' });
    const ct = response.headers['content-type'] || '';
    const isXlsx = ct.includes('spreadsheet') || ct.includes('excel');
    const mimeType = isXlsx
      ? 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'
      : 'text/csv;charset=utf-8;';
    // Auto-correct extension based on actual response
    const base = filename.replace(/\.(xlsx|csv)$/, '');
    const ext  = isXlsx ? '.xlsx' : '.csv';
    const blob = new Blob([response.data], { type: mimeType });
    const url  = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href  = url;
    link.setAttribute('download', base + ext);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  } catch (err) {
    console.error('Download failed:', err);
    alert('Download failed. Check your permissions and try again.');
  } finally {
    if (setLoading) setLoading(false);
  }
};

// ─── Export Card ──────────────────────────────────────────────────────────────
const ExportCard = ({ title, description, icon, exports: exportList }) => {
  const [loadingIndex, setLoadingIndex] = useState(null);

  const handleClick = async (exp, i) => {
    setLoadingIndex(i);
    const filename = `${exp.label.toLowerCase().replace(/\s+/g, '-')}-${new Date().toISOString().split('T')[0]}.csv`;
    await downloadCSV(exp.endpoint, filename);
    setLoadingIndex(null);
  };

  return (
    <div className="card">
      <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', marginBottom: '1rem' }}>
        <span style={{ fontSize: '1.5rem' }}>{icon}</span>
        <div>
          <div style={{ fontWeight: 700, fontFamily: 'var(--font-heading)', fontSize: '0.95rem' }}>{title}</div>
          <div style={{ fontSize: '0.78rem', color: 'var(--text-muted)', marginTop: '0.1rem' }}>{description}</div>
        </div>
      </div>
      <div style={{ display: 'flex', flexDirection: 'column', gap: '0.4rem' }}>
        {exportList.map((exp, i) => (
          <button
            key={i}
            onClick={() => handleClick(exp, i)}
            disabled={loadingIndex !== null}
            style={{
              display: 'flex', alignItems: 'center', justifyContent: 'space-between',
              padding: '0.65rem 0.85rem',
              background: 'var(--bg-hover)', borderRadius: 6,
              border: `1px solid ${loadingIndex === i ? 'var(--accent)' : 'var(--border)'}`,
              color: loadingIndex === i ? 'var(--accent)' : 'var(--text-primary)',
              fontSize: '0.83rem', transition: 'var(--transition)',
              cursor: loadingIndex !== null ? 'not-allowed' : 'pointer',
              opacity: loadingIndex !== null && loadingIndex !== i ? 0.5 : 1,
              width: '100%', textAlign: 'left', fontFamily: 'var(--font-mono)',
            }}
            onMouseEnter={e => { if (loadingIndex === null) { e.currentTarget.style.borderColor = 'var(--accent)'; e.currentTarget.style.color = 'var(--accent)'; }}}
            onMouseLeave={e => { if (loadingIndex !== i) { e.currentTarget.style.borderColor = 'var(--border)'; e.currentTarget.style.color = 'var(--text-primary)'; }}}
          >
            <span>{exp.label}</span>
            <span style={{ fontSize: '0.72rem', color: 'var(--text-muted)', display: 'flex', alignItems: 'center', gap: '0.3rem' }}>
              {loadingIndex === i ? (
                <><span className="spinner" style={{ width: 12, height: 12 }}/> Downloading…</>
              ) : (
                <>↓ CSV</>
              )}
            </span>
          </button>
        ))}
      </div>
    </div>
  );
};

// ─── Main Page ────────────────────────────────────────────────────────────────
export default function ReportsPage() {
  const navigate = useNavigate();
  const [kpiFrom, setKpiFrom] = useState(() => {
    const d = new Date(); d.setDate(d.getDate() - 90);
    return d.toISOString().split('T')[0];
  });
  const [kpiTo, setKpiTo] = useState(() => new Date().toISOString().split('T')[0]);
  const [kpiLoading, setKpiLoading] = useState(false);

  const handleKpiExport = () => {
    downloadCSV(
      `/export/kpis?from=${kpiFrom}&to=${kpiTo}`,
      `kpis-${kpiFrom}-to-${kpiTo}.csv`,
      setKpiLoading
    );
  };

  return (
    <div className="page">
      <Sidebar />
      <div className="main-content">
        <div className="page-header">
          <div>
            <h1 style={{ fontSize: '1.3rem', fontFamily: 'var(--font-heading)' }}>Reports & Exports</h1>
            <p style={{ color: 'var(--text-muted)', fontSize: '0.8rem', marginTop: '0.2rem' }}>
              Download CSV reports — authenticated, no redirect
            </p>
          </div>
        </div>

        <div className="page-body">
          <div className="grid-2" style={{ gap: '1rem' }}>
            <div className="card">
              <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', marginBottom: '1rem' }}>
                <span style={{ fontSize: '1.5rem' }}>€</span>
                <div>
                  <div style={{ fontWeight: 700, fontFamily: 'var(--font-heading)', fontSize: '0.95rem' }}>Cost KPI Dashboard</div>
                  <div style={{ fontSize: '0.78rem', color: 'var(--text-muted)', marginTop: '0.1rem' }}>
                    Estimated vs actual costs by site, material, printer, and technician
                  </div>
                </div>
              </div>
              <button className="btn btn-primary" style={{ width: '100%', justifyContent: 'center' }} onClick={() => navigate('/reports/costs')}>
                Open Cost KPI Dashboard
              </button>
            </div>

            <ExportCard
              title="Requests"
              description="Export request lists by status"
              icon="📋"
              exports={[
                { label: 'All Requests',       endpoint: '/export/requests/all' },
                { label: 'Open Requests',      endpoint: '/export/requests/open' },
                { label: 'Completed Requests', endpoint: '/export/requests/completed' },
                { label: 'Overdue Requests',   endpoint: '/export/requests/overdue' },
                { label: 'Archived Requests',  endpoint: '/export/requests/archived' },
              ]}
            />

            <ExportCard
              title="Workload"
              description="Technician and printer workload reports"
              icon="⚙️"
              exports={[
                { label: 'Technician Workload', endpoint: '/export/workload/technician' },
                { label: 'Printer Workload',    endpoint: '/export/workload/printer' },
              ]}
            />

            <ExportCard
              title="Material Consumption"
              description="Material usage and stock tracking"
              icon="🧵"
              exports={[
                { label: 'Material Consumption Report', endpoint: '/export/materials' },
              ]}
            />

            {/* KPI export with date range */}
            <div className="card">
              <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', marginBottom: '1rem' }}>
                <span style={{ fontSize: '1.5rem' }}>📊</span>
                <div>
                  <div style={{ fontWeight: 700, fontFamily: 'var(--font-heading)', fontSize: '0.95rem' }}>KPI History</div>
                  <div style={{ fontSize: '0.78rem', color: 'var(--text-muted)', marginTop: '0.1rem' }}>
                    Weekly KPIs for a custom date range
                  </div>
                </div>
              </div>
              <div className="grid-2" style={{ marginBottom: '0.75rem' }}>
                <div className="form-group">
                  <label className="form-label">From</label>
                  <DatePicker value={kpiFrom} onChange={setKpiFrom} placeholder="Start date"/>
                </div>
                <div className="form-group">
                  <label className="form-label">To</label>
                  <DatePicker value={kpiTo} onChange={setKpiTo} placeholder="End date"/>
                </div>
              </div>
              <button
                onClick={handleKpiExport}
                disabled={kpiLoading}
                className="btn btn-primary"
                style={{ width: '100%', justifyContent: 'center' }}
              >
                {kpiLoading ? (
                  <><span className="spinner" style={{ width: 14, height: 14 }}/> Downloading…</>
                ) : (
                  <>↓ Download KPI Export (CSV)</>
                )}
              </button>
            </div>

          </div>

          <div className="alert alert-info" style={{ marginTop: '1.5rem' }}>
            <strong>Tip:</strong> All CSV files are UTF-8 with BOM — open directly in Microsoft Excel.
            Double-click the downloaded file or use <em>File → Open</em> in Excel.
          </div>
        </div>
      </div>
    </div>
  );
}
